import { useLocalSearchParams, useRouter, type Href } from 'expo-router';
import { View } from 'react-native';

import { createKangurDuelsHref } from '../duels/duelsHref';
import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileLessonCheckpoints } from '../lessons/useKangurMobileLessonCheckpoints';
import {
  resolveResultsFilterFamily,
  resolveResultsFilterOperation,
} from './results-primitives';
import { ResultsHeader, ResultsOverview, ResultsAssignmentsSection, ResultsBadgesSection, ResultsLessonMasterySection, ResultsDuelsSection, ResultsCheckpointsSection, ResultsListSection } from './components';
import { useKangurMobileResults } from './useKangurMobileResults';
import { useKangurMobileResultsAssignments } from './useKangurMobileResultsAssignments';
import { useKangurMobileResultsLessonMastery } from './useKangurMobileResultsLessonMastery';
import { useKangurMobileResultsBadges } from './useKangurMobileResultsBadges';
import { useKangurMobileResultsDuels } from './useKangurMobileResultsDuels';
import { KangurMobileScrollScreen } from '../shared/KangurMobileUi';
import type { ReactElement } from 'react';

const DUELS_ROUTE = createKangurDuelsHref();
const PROFILE_ROUTE = '/profile' as Href;
const LESSONS_ROUTE = '/lessons' as Href;

function ResultsContent({ 
    results, 
    resultsAssignments, 
    resultsBadges, 
    lessonMastery, 
    duelResults, 
    lessonCheckpoints, 
    filterFamily, 
    filterOperation, 
    lessonFocusSummary, 
    copy, 
    locale, 
    openDuelSession 
}: { 
    results: any; 
    resultsAssignments: any; 
    resultsBadges: any; 
    lessonMastery: any; 
    duelResults: any; 
    lessonCheckpoints: any; 
    filterFamily: string | undefined; 
    filterOperation: string | undefined; 
    lessonFocusSummary: string | null; 
    copy: any; 
    locale: string; 
    openDuelSession: (sessionId: string) => void 
}): ReactElement {
  return (
    <>
      <ResultsOverview results={results} copy={copy} />
      <ResultsAssignmentsSection assignments={resultsAssignments.assignmentItems} copy={copy} />
      <ResultsBadgesSection badges={resultsBadges} copy={copy} profileHref={PROFILE_ROUTE} />
      <ResultsLessonMasterySection mastery={lessonMastery} summary={lessonFocusSummary} copy={copy} />
      <ResultsDuelsSection duelResults={duelResults} duelsHref={DUELS_ROUTE} openDuelSession={openDuelSession} />
      <ResultsCheckpointsSection checkpoints={lessonCheckpoints.recentCheckpoints} copy={copy} lessonsHref={LESSONS_ROUTE} />
      <ResultsListSection results={results} copy={copy} locale={locale} family={filterFamily} operation={filterOperation} />
    </>
  );
}

export function KangurResultsScreen(): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();
  const router = useRouter();
  const params = useLocalSearchParams<{
    family?: string | string[];
    operation?: string | string[];
  }>();
  const filterFamily = resolveResultsFilterFamily(params.family);
  const filterOperation = resolveResultsFilterOperation(params.operation);

  const results = useKangurMobileResults({
    family: filterOperation !== null ? 'all' : filterFamily,
    operation: filterOperation,
  });
  const duelResults = useKangurMobileResultsDuels();
  const resultsAssignments = useKangurMobileResultsAssignments();
  const lessonMastery = useKangurMobileResultsLessonMastery();
  const resultsBadges = useKangurMobileResultsBadges();
  const lessonCheckpoints = useKangurMobileLessonCheckpoints({ limit: 2 });

  const weakestLesson = lessonMastery.weakest[0] ?? null;
  const strongestLesson = lessonMastery.strongest[0] ?? null;

  const lessonFocusSummary = weakestLesson
    ? copy({
        de: `Fokus nach den Ergebnissen: ${weakestLesson.title} braucht noch eine schnelle Wiederholung, bevor du wieder Tempo aufbaust.`,
        en: `Post-results focus: ${weakestLesson.title} still needs a quick review before you build momentum again.`,
        pl: `Fokus po wynikach: ${weakestLesson.title} potrzebuje jeszcze szybkiej powtórki, zanim znowu wejdziesz w tempo.`,
      })
    : (strongestLesson
        ? copy({
            de: `Stabile Stärke: ${strongestLesson.title} hält das Niveau und eignet sich für einen kurzen sicheren Einstieg.`,
            en: `Stable strength: ${strongestLesson.title} is holding its level and works well for a short confidence run.`,
            pl: `Stabilna mocna strona: ${strongestLesson.title} trzyma poziom i nadaje się na krótkie, pewne wejście.`,
          })
        : null);

  const openDuelSession = (sessionId: string): void => {
    router.replace(createKangurDuelsHref({ sessionId }));
  };

  return (
    <KangurMobileScrollScreen contentContainerStyle={{ gap: 18, paddingHorizontal: 20, paddingVertical: 24 }}>
        <View style={{ gap: 14 }}>
          <ResultsHeader copy={copy} />

          {(results.isLoading || !results.isEnabled) ? null : (
            <ResultsContent 
                results={results} 
                resultsAssignments={resultsAssignments} 
                resultsBadges={resultsBadges} 
                lessonMastery={lessonMastery} 
                duelResults={duelResults} 
                lessonCheckpoints={lessonCheckpoints} 
                filterFamily={filterFamily} 
                filterOperation={filterOperation} 
                lessonFocusSummary={lessonFocusSummary} 
                copy={copy} 
                locale={locale} 
                openDuelSession={openDuelSession}
            />
          )}
        </View>
    </KangurMobileScrollScreen>
  );
}

import type { Href } from 'expo-router';
import { Text, View } from 'react-native';

import { useKangurMobileI18n } from '../../i18n/kangurMobileI18n';
import type { KangurMobileLessonCheckpointItem } from '../../lessons/useKangurMobileLessonCheckpoints';
import {
  KangurMobileInsetPanel as InsetPanel,
  KangurMobileLinkButton as LinkButton,
  KangurMobilePill as Pill,
} from '../../shared/KangurMobileUi';
import { formatKangurMobileScoreDateTime } from '../mobileScoreSummary';

function PracticeButton({
  practiceHref,
  title,
}: {
  practiceHref: Href;
  title: string;
}): React.JSX.Element {
  const { copy } = useKangurMobileI18n();
  return (
    <LinkButton
      href={practiceHref}
      label={`${copy({
        de: 'Danach trainieren',
        en: 'Practice after',
        pl: 'Potem trenuj',
      })}: ${title}`}
    />
  );
}

export function LessonCheckpointRow({
  item,
}: {
  item: KangurMobileLessonCheckpointItem;
}): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();

  return (
    <InsetPanel gap={10}>
      <View style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'flex-start', gap: 12 }}>
        <View style={{ flex: 1, gap: 4 }}>
          <Text style={{ color: '#000', fontSize: 16, fontWeight: '800' }}>
            {item.emoji} {item.title}
          </Text>
          <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
            {copy({
              de: `Letztes Ergebnis ${item.lastScorePercent}% • Beherrschung ${item.masteryPercent}%`,
              en: `Last score ${item.lastScorePercent}% • mastery ${item.masteryPercent}%`,
              pl: `Ostatni wynik ${item.lastScorePercent}% • opanowanie ${item.masteryPercent}%`,
            })}
          </Text>
        </View>
        <Pill
          label={`${item.bestScorePercent}%`}
          tone={{ backgroundColor: '#eef2ff', borderColor: '#c7d2fe', textColor: '#4338ca' }}
        />
      </View>

      <Text style={{ color: '#64748b', fontSize: 12, lineHeight: 18 }}>
        {copy({
          de: `Zuletzt gespeichert ${formatKangurMobileScoreDateTime(item.lastCompletedAt, locale)}`,
          en: `Last saved ${formatKangurMobileScoreDateTime(item.lastCompletedAt, locale)}`,
          pl: `Ostatni zapis ${formatKangurMobileScoreDateTime(item.lastCompletedAt, locale)}`,
        })}
      </Text>

      <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
        <LinkButton
          href={item.lessonHref}
          label={`${copy({
            de: 'Zur Lektion zurück',
            en: 'Return to lesson',
            pl: 'Wróć do lekcji',
          })}: ${item.title}`}
          tone='primary'
        />
        {item.practiceHref && (
          <PracticeButton practiceHref={item.practiceHref} title={item.title} />
        )}
      </View>
    </InsetPanel>
  );
}

import type { Href } from 'expo-router';
import { Text, View } from 'react-native';

import { useKangurMobileI18n } from '../../i18n/kangurMobileI18n';
import {
  KangurMobileInsetPanel as InsetPanel,
  KangurMobileLinkButton as LinkButton,
  KangurMobilePill as Pill,
} from '../../shared/KangurMobileUi';
import { formatKangurMobileScoreDateTime } from '../mobileScoreSummary';
import { getAccuracyTone } from '../results-primitives';
import type { KangurMobileResultsLessonMasteryItem } from '../useKangurMobileResultsLessonMastery';

export function LessonMasteryRow({
  insight,
  title,
}: {
  insight: KangurMobileResultsLessonMasteryItem;
  title: string;
}): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();
  const masteryTone = getAccuracyTone(insight.masteryPercent);
  const lastAttemptLabel =
    insight.lastCompletedAt !== null && insight.lastCompletedAt !== undefined
      ? formatKangurMobileScoreDateTime(insight.lastCompletedAt, locale)
      : copy({
          de: 'kein Datum',
          en: 'no date',
          pl: 'brak daty',
        });

  return (
    <InsetPanel gap={10}>
      <View
        style={{
          flexDirection: 'row',
          justifyContent: 'space-between',
          alignItems: 'flex-start',
          gap: 12,
        }}
      >
        <View style={{ flex: 1, gap: 4 }}>
          <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>{title}</Text>
          <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '800' }}>
            {insight.emoji} {insight.title}
          </Text>
          <Text style={{ color: '#475569', fontSize: 13, lineHeight: 18 }}>
            {copy({
              de: `Versuche ${insight.attempts} • letztes Ergebnis ${insight.lastScorePercent}%`,
              en: `Attempts ${insight.attempts} • last score ${insight.lastScorePercent}%`,
              pl: `Próby ${insight.attempts} • ostatni wynik ${insight.lastScorePercent}%`,
            })}
          </Text>
        </View>
        <Pill label={`${insight.masteryPercent}%`} tone={masteryTone} />
      </View>

      <Text style={{ color: '#64748b', fontSize: 12, lineHeight: 18 }}>
        {copy({
          de: `Bestes Ergebnis ${insight.bestScorePercent}% • letzter Versuch ${lastAttemptLabel}`,
          en: `Best score ${insight.bestScorePercent}% • last attempt ${lastAttemptLabel}`,
          pl: `Najlepszy wynik ${insight.bestScorePercent}% • ostatnia próba ${lastAttemptLabel}`,
        })}
      </Text>

      <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
        <LinkButton
          href={insight.lessonHref}
          label={copy({
            de: 'Lektion öffnen',
            en: 'Open lesson',
            pl: 'Otwórz lekcję',
          })}
          style={{ paddingHorizontal: 12 }}
          tone='primary'
          verticalPadding={9}
        />
        {renderResultsPracticeLink({
          href: insight.practiceHref,
          label: copy({
            de: 'Danach trainieren',
            en: 'Practice after',
            pl: 'Potem trenuj',
          }),
        })}
      </View>
    </InsetPanel>
  );
}

export function renderResultsPracticeLink({
  href,
  label,
}: {
  href: Href | null;
  label: string;
}): React.JSX.Element | null {
  if (href === null || href === undefined) {
    return null;
  }

  return (
    <LinkButton
      href={href}
      label={label}
      style={{ paddingHorizontal: 12 }}
      verticalPadding={9}
    />
  );
}

import type { Href } from 'expo-router';
import { Text, View } from 'react-native';

import { useKangurMobileI18n } from '../../i18n/kangurMobileI18n';
import { createKangurPracticeHref } from '../../practice/practiceHref';
import {
  type KangurMobileOperationPerformance,
  formatKangurMobileScoreOperation,
} from '../mobileScoreSummary';
import {
  KangurMobileInsetPanel as InsetPanel,
  KangurMobileLinkButton as LinkButton,
  KangurMobilePill as Pill,
} from '../../shared/KangurMobileUi';
import { createKangurResultsHref } from '../resultsHref';
import { getOperationTone } from '../results-primitives';

export function OperationInsightCard({
  description,
  lessonHref,
  operation,
  practiceLabel,
  title,
}: {
  description: string;
  lessonHref?: Href;
  operation: KangurMobileOperationPerformance;
  practiceLabel: string;
  title: string;
}): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();
  const operationTone = getOperationTone(operation.family);

  return (
    <InsetPanel gap={10} style={{ flexBasis: '48%' }}>
      <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>{title}</Text>
      <Text style={{ color: '#0f172a', fontSize: 18, fontWeight: '800' }}>
        {formatKangurMobileScoreOperation(operation.operation, locale)}
      </Text>
      <Text style={{ color: '#475569', fontSize: 13, lineHeight: 18 }}>{description}</Text>

      <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
        <Pill
          label={copy({
            de: `Durchschnitt ${operation.averageAccuracyPercent}%`,
            en: `Average ${operation.averageAccuracyPercent}%`,
            pl: `Średnio ${operation.averageAccuracyPercent}%`,
          })}
          tone={operationTone}
        />
        <Pill
          label={copy({
            de: `Ergebnisse ${operation.sessions}`,
            en: `Results ${operation.sessions}`,
            pl: `Wyniki ${operation.sessions}`,
          })}
          tone={{
            backgroundColor: '#ffffff',
            borderColor: '#cbd5e1',
            textColor: '#475569',
          }}
        />
      </View>

      <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
        <LinkButton
          href={createKangurPracticeHref(operation.operation)}
          label={practiceLabel}
          tone='primary'
        />

        {lessonHref !== undefined && lessonHref !== null ? (
          <LinkButton
            href={lessonHref}
            label={copy({
              de: 'Lektion öffnen',
              en: 'Open lesson',
              pl: 'Otwórz lekcję',
            })}
          />
        ) : null}

        <LinkButton
          href={createKangurResultsHref({
            operation: operation.operation,
          })}
          label={copy({
            de: 'Modusverlauf',
            en: 'Mode history',
            pl: 'Historia trybu',
          })}
        />
      </View>
    </InsetPanel>
  );
}

import { Text } from 'react-native';

import { useKangurMobileI18n } from '../../i18n/kangurMobileI18n';
import {
  KangurMobileInsetPanel as InsetPanel,
  KangurMobileLinkButton as LinkButton,
  KangurMobileMutedActionChip as MutedActionChip,
  KangurMobilePill as Pill,
} from '../../shared/KangurMobileUi';
import { translateKangurMobileActionLabel } from '../../shared/translateKangurMobileActionLabel';
import type { KangurMobileResultsAssignmentItem } from '../useKangurMobileResultsAssignments';

import { Text, View } from 'react-native';

import { useKangurMobileI18n } from '../../i18n/kangurMobileI18n';
import {
  KangurMobileInsetPanel as InsetPanel,
  KangurMobileLinkButton as LinkButton,
  KangurMobileMutedActionChip as MutedActionChip,
  KangurMobilePill as Pill,
  type KangurMobileTone as Tone,
} from '../../shared/KangurMobileUi';
import { translateKangurMobileActionLabel } from '../../shared/translateKangurMobileActionLabel';
import type { KangurMobileResultsAssignmentItem } from '../useKangurMobileResultsAssignments';

const getPriorityTone = (priority: string): Tone => {
  if (priority === 'high') return { backgroundColor: '#fef2f2', borderColor: '#fecaca', textColor: '#b91c1c' };
  if (priority === 'medium') return { backgroundColor: '#fffbeb', borderColor: '#fde68a', textColor: '#b45309' };
  return { backgroundColor: '#eff6ff', borderColor: '#bfdbfe', textColor: '#1d4ed8' };
};

const getPriorityLabel = (priority: string, copy: ReturnType<typeof useKangurMobileI18n>['copy']): string => {
  if (priority === 'high') return copy({ de: 'Hohe Priorität', en: 'High priority', pl: 'Priorytet wysoki' });
  if (priority === 'medium') return copy({ de: 'Mittlere Priorität', en: 'Medium priority', pl: 'Priorytet średni' });
  return copy({ de: 'Niedrige Priorität', en: 'Low priority', pl: 'Priorytet niski' });
};

function PriorityBadge({ priority, copy }: { priority: string; copy: ReturnType<typeof useKangurMobileI18n>['copy'] }) {
  return <Pill label={getPriorityLabel(priority, copy)} tone={getPriorityTone(priority)} />;
}

function AssignmentInfo({ item, copy }: { item: KangurMobileResultsAssignmentItem; copy: ReturnType<typeof useKangurMobileI18n>['copy'] }) {
  return (
    <>
      <Text style={{ color: '#0f172a', fontSize: 15, fontWeight: '800' }}>{item.title}</Text>
      <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>{item.description}</Text>
      <Text style={{ color: '#64748b', fontSize: 12, lineHeight: 18 }}>
        {copy({ de: `Ziel: ${item.target}`, en: `Goal: ${item.target}`, pl: `Cel: ${item.target}` })}
      </Text>
    </>
  );
}

function AssignmentAction({ item, copy, locale }: { item: KangurMobileResultsAssignmentItem; copy: ReturnType<typeof useKangurMobileI18n>['copy']; locale: string }) {
  const label = translateKangurMobileActionLabel(item.action.label, locale);
  if (item.href) return <LinkButton href={item.href} label={label} tone='primary' />;

  return (
    <MutedActionChip
      compact
      label={`${label} · ${copy({ de: 'bald', en: 'soon', pl: 'wkrotce' })}`}
    />
  );
}

export function ResultsAssignmentRow({
  item,
}: {
  item: KangurMobileResultsAssignmentItem;
}): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();
  return (
    <InsetPanel gap={8} padding={12} style={{ borderRadius: 18, backgroundColor: '#ffffff' }}>
      <PriorityBadge priority={item.priority} copy={copy} />
      <AssignmentInfo item={item} copy={copy} />
      <AssignmentAction item={item} copy={copy} locale={locale} />
    </InsetPanel>
  );
}

import { View, Text } from 'react-native';
import { Card } from '../../shared/KangurMobileUi';
import { ResultsAssignmentRow } from './ResultsAssignmentRow';
import { type KangurMobileCopy } from '../../i18n/kangurMobileI18n';

import { type KangurMobileResultsAssignmentItem } from '../useKangurMobileResultsAssignments';

interface ResultsAssignmentsSectionProps {
  assignmentItems: KangurMobileResultsAssignmentItem[];
  copy: KangurMobileCopy;
}

export function ResultsAssignmentsSection({
  assignmentItems,
  copy,
}: ResultsAssignmentsSectionProps): React.JSX.Element {
  return (
    <Card>
      <View style={{ gap: 4 }}>
        <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>
          {copy({
            de: 'Nach den Ergebnissen',
            en: 'After results',
            pl: 'Po wynikach',
          })}
        </Text>
        <Text style={{ color: '#0f172a', fontSize: 18, fontWeight: '800' }}>
          {copy({
            de: 'Plan nach den Ergebnissen',
            en: 'Post-results plan',
            pl: 'Plan po wynikach',
          })}
        </Text>
        <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
          {copy({
            de: 'Verwandle die letzten Ergebnisse direkt in die nächsten Schritte, ohne den Trainingsfluss zu verlieren.',
            en: 'Turn the latest results directly into the next steps without losing the training flow.',
            pl: 'Zamień ostatnie wyniki od razu w kolejne kroki, bez gubienia rytmu treningu.',
          })}
        </Text>
      </View>

      {assignmentItems.length === 0 ? (
        <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
          {copy({
            de: 'Es gibt noch keine Aufgaben. Öffne Lektionen oder absolviere weitere Trainings, um den nächsten Plan aufzubauen.',
            en: 'There are no tasks yet. Open lessons or complete more practice to build the next plan.',
            pl: 'Nie ma jeszcze zadań. Otwórz lekcje albo wykonaj kolejne treningi, aby zbudować następny plan.',
          })}
        </Text>
      ) : (
        <View style={{ gap: 10 }}>
          {assignmentItems.map((item) => (
            <ResultsAssignmentRow key={item.assignment.id} item={item} />
          ))}
        </View>
      )}
    </Card>
  );
}

import { View, Text } from 'react-native';
import { Card, KangurMobileSummaryChip, LinkButton } from '../../shared/KangurMobileUi';
import { ResultsBadgeChip } from '../results-primitives';
import { type KangurMobileCopy } from '../../i18n/kangurMobileI18n';
import { type KangurMobileResultsBadgeItem } from '../useKangurMobileResultsBadges';

interface ResultsBadgesSectionProps {
  resultsBadges: {
    unlockedBadges: number;
    totalBadges: number;
    remainingBadges: number;
    recentBadges: KangurMobileResultsBadgeItem[];
  };
  copy: KangurMobileCopy;
  profileHref: string;
}

export function ResultsBadgesSection({
  resultsBadges,
  copy,
  profileHref,
}: ResultsBadgesSectionProps): React.JSX.Element {
  return (
    <Card>
      <View style={{ gap: 4 }}>
        <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>
          {copy({ de: 'Abzeichen', en: 'Badges', pl: 'Odznaki' })}
        </Text>
        <Text style={{ color: '#0f172a', fontSize: 18, fontWeight: '800' }}>
          {copy({ de: 'Abzeichen-Zentrale', en: 'Badge hub', pl: 'Centrum odznak' })}
        </Text>
        <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
          {copy({
            de: 'Behalte im Blick, was schon freigeschaltet ist und welches Ziel am nächsten an der nächsten Abzeichenstufe liegt.',
            en: 'Keep track of what is already unlocked and which goal is closest to the next badge threshold.',
            pl: 'Śledź, co jest już odblokowane i który cel jest najbliżej kolejnego progu odznaki.',
          })}
        </Text>
      </View>

      <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
        <KangurMobileSummaryChip
          label={copy({
            de: `Freigeschaltet ${resultsBadges.unlockedBadges}/${resultsBadges.totalBadges}`,
            en: `Unlocked ${resultsBadges.unlockedBadges}/${resultsBadges.totalBadges}`,
            pl: `Odblokowane ${resultsBadges.unlockedBadges}/${resultsBadges.totalBadges}`,
          })}
        />
        <KangurMobileSummaryChip
          label={copy({
            de: `Offen ${resultsBadges.remainingBadges}`,
            en: `Remaining ${resultsBadges.remainingBadges}`,
            pl: `Do zdobycia ${resultsBadges.remainingBadges}`,
          })}
          backgroundColor='#fffbeb'
          borderColor='#fde68a'
          textColor='#b45309'
        />
      </View>

      {resultsBadges.recentBadges.length === 0 ? (
        <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
          {copy({
            de: 'Es gibt noch keine lokal freigeschalteten Abzeichen. Schließe Lektionen, Trainings oder Spiele ab, damit sie hier erscheinen.',
            en: 'There are no locally unlocked badges yet. Finish lessons, practice runs, or games so they appear here.',
            pl: 'Nie ma jeszcze lokalnie odblokowanych odznak. Ukończ lekcje, treningi albo gry, aby pojawiły się tutaj.',
          })}
        </Text>
      ) : (
        <View style={{ gap: 10 }}>
          <Text style={{ color: '#0f172a', fontSize: 15, fontWeight: '800' }}>
            {copy({ de: 'Zuletzt freigeschaltet', en: 'Recently unlocked', pl: 'Ostatnio odblokowane' })}
          </Text>
          <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
            {resultsBadges.recentBadges.map((item) => (
              <ResultsBadgeChip key={item.id} item={item} />
            ))}
          </View>
        </View>
      )}

      <LinkButton
        href={profileHref}
        label={copy({
          de: 'Profil und Abzeichen öffnen',
          en: 'Open profile and badges',
          pl: 'Otwórz profil i odznaki',
        })}
      />
    </Card>
  );
}

import { View, Text } from 'react-native';
